mapper.select:
SELECT ID, PLAN_CODE, PLAN_NAME, ROUTE_ID, PATROL_TYPE, INITIAL_DATE, SET_DATE, IS_SINGLE, PATROL_ID, PATROL_NAME, RECENTLY_TASK_DATE, STATUS, CREATE_BY, CREATE_TIME, UPDATE_BY, UPDATE_TIME, TIME_LIMIT FROM E_PATROL_PLAN WHERE 1 = 1
AND PLAN_CODE LIKE #{planCode}
AND PLAN_NAME LIKE #{planName}
AND ROUTE_ID = #{routeId}
AND PATROL_TYPE = #{patrolType}

mapper.insert:
INSERT INTO E_PATROL_TASK( ID, PLAN_ID, ROUTE_ID, PATROL_ID, PATROL_NAME, START_TIME, END_TIME, STATUS, CREATE_BY, CREATE_TIME ) (
select #{item.id}, #{item.planId}, #{item.routeId}, #{item.patrolId}, #{item.patrolName}, #{item.startTime}, #{item.endTime}, #{item.status}, #{item.loginUserId,jdbcType=BIGINT}, #{item.now,jdbcType=TIMESTAMP}
from dual
)

INSERT INTO E_PATROL_TASK_SUB( ID, EQUIP_ID, EQUIP_NAME, STATUS , IS_ABNORMAL, IS_REPAIR )
(
select #{item.id}, #{item.equipId}, #{item.equipName}, #{item.status}, #{item.isAbnormal}, #{item.isRepair}
from dual
)

